import{_ as e,o as s,c as t,a2 as l}from"./chunks/framework.iesXg5kS.js";const h=JSON.parse('{"title":"获取最新的资讯：last30days-skill","description":"","frontmatter":{},"headers":[],"relativePath":"skills/信息类/获取最新的资讯.md","filePath":"skills/信息类/获取最新的资讯.md","lastUpdated":1781229017000}'),i={name:"skills/信息类/获取最新的资讯.md"};function n(r,a,o,p,d,c){return s(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="获取最新的资讯-last30days-skill" tabindex="-1">获取最新的资讯：last30days-skill <a class="header-anchor" href="#获取最新的资讯-last30days-skill" aria-label="Permalink to &quot;获取最新的资讯：last30days-skill&quot;">​</a></h1><p>仓库地址：<a href="https://github.com/mvanhorn/last30days-skill" target="_blank" rel="noreferrer">https://github.com/mvanhorn/last30days-skill</a></p><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p><code>/last30days</code> 是一个 AI Agent 驱动的「全网最近 30 天」搜索 Skill。一条命令，让 AI 同时去 Reddit、X（Twitter）、YouTube、TikTok、Hacker News、Polymarket、GitHub、Instagram、Threads、Bluesky、Pinterest、Perplexity 等十几个平台搜索同一个话题，然后由一个 AI 评审 Agent 综合所有结果，输出一份带引用的简报。</p><p>用法示例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/last30days Peter Steinberger</span></span>
<span class="line"><span>/last30days OpenAI vs Anthropic vs xAI</span></span>
<span class="line"><span>/last30days 环球影城 Epic Universe --emit=html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>支持 Claude Code、Codex、Cursor、Gemini CLI、Copilot 等 50+ 宿主。</p><h2 id="核心优势" tabindex="-1">核心优势 <a class="header-anchor" href="#核心优势" aria-label="Permalink to &quot;核心优势&quot;">​</a></h2><ol><li><p><strong>打通信息孤岛</strong>：Google 搜不到 Reddit 评论和 X 帖子，ChatGPT 搜不了 X 和 TikTok，Gemini 没有 Reddit，Claude 原生都没有。这个 Skill 让你「自带 API Key 和浏览器登录态」，一次性聚合所有平台。</p></li><li><p><strong>按真人投票排序，而不是 SEO</strong>：用 Reddit 点赞数、X 点赞、YouTube 播放量、TikTok 互动、Polymarket 真金白银下注的赔率作为信号权重，挖出真正被人讨论的内容，而不是被 SEO 操纵的网页。</p></li><li><p><strong>智能预搜索（v3 杀手锏）</strong>：搜「OpenClaw」会自动解析出作者 @steipete、相关 subreddit、YouTube 频道、TikTok 标签，先理解话题再发起搜索，而不是傻搜关键词。</p></li><li><p><strong>Polymarket 预测市场</strong>：把真金白银押注的赔率作为「事件是否会发生」的可信信号，比专家观点更难反驳。</p></li><li><p><strong>GitHub 人物模式</strong>：搜人时自动切到 author 维度，告诉你这个人这个月合并了多少 PR、合并率、在做什么项目。</p></li><li><p><strong>可分享的 HTML 简报</strong>：加 <code>--emit=html</code> 直接产出深色模式、可打印、可离线、带引用的独立 HTML 文件，方便丢进 Slack / 邮件 / Notion。</p></li><li><p><strong>零配置启动</strong>：Reddit、HN、Polymarket、GitHub 开箱即用；X、YouTube、TikTok 等通过向导 30 秒解锁。</p></li></ol><h2 id="典型使用场景" tabindex="-1">典型使用场景 <a class="header-anchor" href="#典型使用场景" aria-label="Permalink to &quot;典型使用场景&quot;">​</a></h2><ul><li>见客户/面试前 30 秒摸底一个人最近在做什么</li><li>出差/旅行前看目的地最近的真实评价</li><li>选型对比工具（A vs B vs C），自动拉取三方的最新讨论</li><li>跟踪某个快速变化的领域（如 AI），获取比模型训练数据更新的社区共识</li></ul>`,11)])])}const k=e(i,[["render",n]]);export{h as __pageData,k as default};
